#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding vaccinations-assessment (14 tables)..."

cargo loco generate scaffold patient \
    patient_name:string! \
    date_of_birth:date \
    patient_sex:string! \
    patient_age:string! \
    nhs_number:string^ \
    gp_practice:string! \
    contact_phone:string! \
    contact_email:string! \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold immunization_history \
    assessment:references \
    has_vaccination_record:string! \
    record_source:string! \
    last_review_date:date \
    previous_adverse_reactions:string! \
    adverse_reaction_details:text! \
    immunocompromised:string! \
    immunocompromised_details:text! \
    --htmx

cargo loco generate scaffold childhood_vaccinations \
    assessment:references \
    dtap_ipv_hib_hepb:int \
    pneumococcal:int \
    rotavirus:int \
    meningitis_b:int \
    mmr:int \
    hib_menc:int \
    preschool_booster:int \
    --htmx

cargo loco generate scaffold adult_vaccinations \
    assessment:references \
    td_ipv_booster:int \
    hpv:int \
    meningitis_acwy:int \
    influenza_annual:int \
    covid19:int \
    shingles:int \
    pneumococcal_ppv:int \
    --htmx

cargo loco generate scaffold travel_vaccinations \
    assessment:references \
    travel_planned:string! \
    travel_destination:string! \
    hepatitis_a:int \
    hepatitis_b:int \
    typhoid:int \
    yellow_fever:int \
    rabies:int \
    japanese_encephalitis:int \
    --htmx

cargo loco generate scaffold occupational_vaccinations \
    assessment:references \
    occupation:string! \
    healthcare_worker:string! \
    hepatitis_b_occupational:int \
    influenza_occupational:int \
    varicella:int \
    bcg_tuberculosis:int \
    --htmx

cargo loco generate scaffold contraindications_allergies \
    assessment:references \
    egg_allergy:string! \
    gelatin_allergy:string! \
    latex_allergy:string! \
    neomycin_allergy:string! \
    pregnant:string! \
    pregnancy_weeks:string! \
    severe_illness:string! \
    previous_anaphylaxis:string! \
    anaphylaxis_details:text! \
    --htmx

cargo loco generate scaffold consent_information \
    assessment:references \
    information_provided:int \
    risks_explained:int \
    benefits_explained:int \
    questions_answered:int \
    consent_given:string! \
    consent_date:date \
    guardian_consent:string! \
    --htmx

cargo loco generate scaffold administration_record \
    assessment:references \
    vaccine_name:string! \
    batch_number:string! \
    expiry_date:date \
    administration_site:string! \
    administration_route:string! \
    dose_number:string! \
    administered_by:string! \
    administration_date:date \
    --htmx

cargo loco generate scaffold clinical_review \
    assessment:references \
    post_vaccination_observation:int \
    immediate_reaction:string! \
    reaction_details:text! \
    next_dose_due:date \
    catch_up_schedule_needed:string! \
    referral_needed:string! \
    clinician_notes:text! \
    reviewing_clinician:string! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    vaccination_level:string! \
    vaccination_score:int! \
    graded_at:ts \
    --htmx

cargo loco generate scaffold fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    concern_level:string! \
    --htmx

cargo loco generate scaffold additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
